--
-- Corrige o schema real do SDQ_PR no banco: os rotulos genericos
-- ("N. Resposta do item") ficaram gravados em administration_schema desde a
-- migration original (20260702_four_tests_validation.sql). O arquivo local
-- psychosys/data/test-definitions/four-tests.json foi atualizado com o texto
-- oficial dos 25 itens, mas esse JSON local nunca foi a fonte em tempo de
-- execucao -- quem alimenta a tela e o administration_schema salvo direto no
-- banco. Esta migration substitui apenas o array de campos da secao "items"
-- (indice 1), preservando respondent e impact intactos.

UPDATE public.test_forms
SET administration_schema = jsonb_set(
  administration_schema,
  '{sections,1,fields}',
  $sdqitems$[{"id": "item_1", "span": 12, "type": "radio", "label": "1. Tem consideração pelos sentimentos de outras pessoas", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_2", "span": 12, "type": "radio", "label": "2. Não consegue parar sentado quando tem que fazer a lição ou comer; mexe-se muito, esbarrando em coisas, derrubando coisas", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_3", "span": 12, "type": "radio", "label": "3. Muitas vezes se queixa de dor de cabeça, dor de barriga ou enjôo", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_4", "span": 12, "type": "radio", "label": "4. Tem boa vontade em compartilhar doces, brinquedos, lápis ... com outras crianças", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_5", "span": 12, "type": "radio", "label": "5. Frequentemente tem acessos de raiva ou crises de birra", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_6", "span": 12, "type": "radio", "label": "6. É solitário, prefere brincar sozinho", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_7", "span": 12, "type": "radio", "label": "7. Geralmente é obediente e faz normalmente o que os adultos lhe pedem", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_8", "span": 12, "type": "radio", "label": "8. Tem muitas preocupações, muitas vezes parece preocupado com tudo", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_9", "span": 12, "type": "radio", "label": "9. Tenta ser atencioso se alguém parece magoado, aflito ou se sentindo mal", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_10", "span": 12, "type": "radio", "label": "10. Está sempre agitado, balançando as pernas ou mexendo as mãos", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_11", "span": 12, "type": "radio", "label": "11. Tem pelo menos um bom amigo ou amiga", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_12", "span": 12, "type": "radio", "label": "12. Frequentemente briga com outras crianças ou as amedronta", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_13", "span": 12, "type": "radio", "label": "13. Frequentemente parece triste, desanimado ou choroso", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_14", "span": 12, "type": "radio", "label": "14. Em geral, é querido por outras crianças", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_15", "span": 12, "type": "radio", "label": "15. Facilmente perde a concentração", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_16", "span": 12, "type": "radio", "label": "16. Fica inseguro quando tem que fazer alguma coisa pela primeira vez, facilmente perde a confiança em si mesmo", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_17", "span": 12, "type": "radio", "label": "17. É gentil com crianças mais novas", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_18", "span": 12, "type": "radio", "label": "18. Frequentemente engana ou mente", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_19", "span": 12, "type": "radio", "label": "19. Outras crianças 'pegam no pé' ou atormentam-no", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_20", "span": 12, "type": "radio", "label": "20. Frequentemente se oferece para ajudar outras pessoas (pais, professores, outras crianças)", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_21", "span": 12, "type": "radio", "label": "21. Pensa nas coisas antes de fazê-las", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_22", "span": 12, "type": "radio", "label": "22. Rouba coisas de casa, da escola ou de outros lugares", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_23", "span": 12, "type": "radio", "label": "23. Se dá melhor com adultos do que com outras crianças", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_24", "span": 12, "type": "radio", "label": "24. Tem muitos medos, assusta-se facilmente", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}, {"id": "item_25", "span": 12, "type": "radio", "label": "25. Completa as tarefas que começa, tem boa concentração", "options": [{"label": "Falso", "value": "0"}, {"label": "Mais ou menos", "value": "1"}, {"label": "Verdadeiro", "value": "2"}], "required": true}]$sdqitems$::jsonb
)
WHERE code = 'SDQ_PR';
